//! Agent-to-Agent (A2A) message envelope primitives.
//!
//! Defines a canonical, signed message envelope that agents can use to
//! communicate in a tamper-evident, verifiable way — regardless of transport
//! (scratchpad, HTTP inbox, future channels).
//!
//! # Format (canonical bytes)
//!
//! ```text
//! from\nto\nnonce\ntimestamp_ms\ncontent_type\npayload_hash_hex
//! ```
//!
//! All fields separated by a single `\n`. The signature covers these bytes
//! exactly.  `payload_hash_hex` is the lowercase hex SHA-256 of the raw
//! payload bytes.
//!
//! # Security properties
//! * Ed25519 signature binds `from`, `to`, `nonce`, `timestamp`, and payload hash.
//! * The nonce prevents replay attacks within the same timestamp window.
//! * Receivers SHOULD verify the signature against the sender's registered pubkey.

use ed25519_dalek::{Signature, Signer, SigningKey, Verifier, VerifyingKey};
use serde::{Deserialize, Serialize};
use sha2::{Digest, Sha256};

// ── Types ─────────────────────────────────────────────────────────

/// Canonical A2A message envelope.
///
/// Transmitted as JSON; the `signature` field is over the canonical bytes
/// (see [`A2AMessage::canonical_bytes`]).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct A2AMessage {
    /// Sender agent identifier.
    pub from: String,
    /// Recipient agent identifier (or `"*"` for broadcast).
    pub to: String,
    /// Random nonce — hex, ≥ 16 bytes → ≥ 32 hex chars.
    pub nonce: String,
    /// Milliseconds since Unix epoch.
    pub timestamp_ms: u64,
    /// Ed25519 signature over canonical bytes (128-char lowercase hex of 64 bytes).
    pub signature: String,
    /// MIME-like content type descriptor, e.g. `"application/json"` or `"text/plain"`.
    pub content_type: String,
    /// Raw payload bytes (arbitrary, opaque to the envelope layer).
    #[serde(with = "serde_bytes_as_base64")]
    pub payload: Vec<u8>,
}

/// Serde helper: serialize Vec<u8> as base64, deserialize from base64.
mod serde_bytes_as_base64 {
    use serde::{Deserialize, Deserializer, Serialize, Serializer};

    pub fn serialize<S>(bytes: &[u8], s: S) -> Result<S::Ok, S::Error>
    where
        S: Serializer,
    {
        // Use standard base64 alphabet
        let b64 = encode_base64(bytes);
        b64.serialize(s)
    }

    pub fn deserialize<'de, D>(d: D) -> Result<Vec<u8>, D::Error>
    where
        D: Deserializer<'de>,
    {
        let s = String::deserialize(d)?;
        decode_base64(&s).map_err(serde::de::Error::custom)
    }

    fn encode_base64(input: &[u8]) -> String {
        const CHARS: &[u8] = b"ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";
        let cap = input.len().div_ceil(3) * 4;
        let mut out = String::with_capacity(cap);
        for chunk in input.chunks(3) {
            let b0 = chunk[0] as usize;
            let b1 = if chunk.len() > 1 {
                chunk[1] as usize
            } else {
                0
            };
            let b2 = if chunk.len() > 2 {
                chunk[2] as usize
            } else {
                0
            };
            out.push(CHARS[b0 >> 2] as char);
            out.push(CHARS[((b0 & 3) << 4) | (b1 >> 4)] as char);
            if chunk.len() > 1 {
                out.push(CHARS[((b1 & 0xF) << 2) | (b2 >> 6)] as char);
            } else {
                out.push('=');
            }
            if chunk.len() > 2 {
                out.push(CHARS[b2 & 0x3F] as char);
            } else {
                out.push('=');
            }
        }
        out
    }

    fn decode_base64(input: &str) -> Result<Vec<u8>, String> {
        let input = input.trim_end_matches('=');
        let mut out = Vec::with_capacity(input.len() * 3 / 4);
        let mut buf = 0u32;
        let mut bits = 0u8;
        for ch in input.bytes() {
            let v = match ch {
                b'A'..=b'Z' => ch - b'A',
                b'a'..=b'z' => ch - b'a' + 26,
                b'0'..=b'9' => ch - b'0' + 52,
                b'+' => 62,
                b'/' => 63,
                _ => return Err(format!("invalid base64 char: {ch}")),
            } as u32;
            buf = (buf << 6) | v;
            bits += 6;
            if bits >= 8 {
                bits -= 8;
                out.push((buf >> bits) as u8);
                buf &= (1 << bits) - 1;
            }
        }
        Ok(out)
    }
}

// ── Canonical bytes ───────────────────────────────────────────────

impl A2AMessage {
    /// Build the canonical bytes that are signed / verified.
    ///
    /// Format: `from\nto\nnonce\ntimestamp_ms\ncontent_type\npayload_hash_hex`
    ///
    /// `payload_hash_hex` is the lowercase hex SHA-256 of `self.payload`.
    pub fn canonical_bytes(&self) -> Vec<u8> {
        let payload_hash = {
            let mut h = Sha256::new();
            h.update(&self.payload);
            hex::encode(h.finalize())
        };
        format!(
            "{}\n{}\n{}\n{}\n{}\n{}",
            self.from, self.to, self.nonce, self.timestamp_ms, self.content_type, payload_hash
        )
        .into_bytes()
    }

    /// Sign this message with a 32-byte Ed25519 secret key.
    ///
    /// Sets `self.signature` to the 128-char lowercase hex of the 64-byte signature.
    ///
    /// # Errors
    /// Returns `Err(String)` if the key is invalid.
    pub fn sign(&mut self, sk: &[u8; 32]) -> Result<(), String> {
        let payload = self.canonical_bytes();
        let signing_key = SigningKey::from_bytes(sk);
        let sig: Signature = signing_key.sign(&payload);
        self.signature = hex::encode(sig.to_bytes());
        Ok(())
    }

    /// Verify this message's signature against a 32-byte Ed25519 public key.
    ///
    /// Returns `true` if the signature is valid for the stored `from`, `to`,
    /// `nonce`, `timestamp_ms`, `content_type`, and `payload`.
    pub fn verify(&self, pk: &[u8; 32]) -> bool {
        let Ok(verifying_key) = VerifyingKey::from_bytes(pk) else {
            return false;
        };
        let Ok(sig_bytes) = hex::decode(&self.signature) else {
            return false;
        };
        let Ok(sig_arr): Result<[u8; 64], _> = sig_bytes.try_into() else {
            return false;
        };
        let signature = Signature::from_bytes(&sig_arr);
        let payload = self.canonical_bytes();
        verifying_key.verify(&payload, &signature).is_ok()
    }

    /// Build a new unsigned envelope (signature is empty — call [`sign`] before sending).
    ///
    /// [`sign`]: A2AMessage::sign
    pub fn build(
        from: impl Into<String>,
        to: impl Into<String>,
        nonce: impl Into<String>,
        timestamp_ms: u64,
        content_type: impl Into<String>,
        payload: Vec<u8>,
    ) -> Self {
        A2AMessage {
            from: from.into(),
            to: to.into(),
            nonce: nonce.into(),
            timestamp_ms,
            signature: String::new(),
            content_type: content_type.into(),
            payload,
        }
    }
}

// ── WASM exports ─────────────────────────────────────────────────

/// WASM: build and sign an A2A message.
///
/// Parameters:
/// * `from_id`      — sender agent identifier
/// * `to_id`        — recipient agent identifier
/// * `nonce_hex`    — 32-char hex nonce (16 random bytes)
/// * `timestamp_ms` — milliseconds since epoch
/// * `content_type` — e.g. `"application/json"`
/// * `payload_b64`  — base64-encoded payload bytes
/// * `sk_hex`       — 64-char hex of the 32-byte secret key
///
/// Returns JSON-serialized [`A2AMessage`], or `{"error":"..."}`.
#[cfg(feature = "wasm")]
#[wasm_bindgen::prelude::wasm_bindgen]
pub fn a2a_build_and_sign(
    from_id: &str,
    to_id: &str,
    nonce_hex: &str,
    timestamp_ms: f64,
    content_type: &str,
    payload_b64: &str,
    sk_hex: &str,
) -> String {
    let Ok(sk_bytes) = hex::decode(sk_hex) else {
        return r#"{"error":"invalid sk_hex"}"#.to_string();
    };
    let Ok(sk_arr): Result<[u8; 32], _> = sk_bytes.try_into() else {
        return r#"{"error":"sk must be 32 bytes"}"#.to_string();
    };

    // Decode base64 payload
    let payload = match decode_b64_simple(payload_b64) {
        Ok(b) => b,
        Err(e) => return format!(r#"{{"error":"invalid payload_b64: {e}"}}"#),
    };

    let mut msg = A2AMessage::build(
        from_id,
        to_id,
        nonce_hex,
        timestamp_ms as u64,
        content_type,
        payload,
    );

    if let Err(e) = msg.sign(&sk_arr) {
        return format!(r#"{{"error":"sign failed: {e}"}}"#);
    }

    serde_json::to_string(&msg)
        .unwrap_or_else(|e| format!(r#"{{"error":"serialize failed: {e}"}}"#))
}

/// WASM: verify an A2A message JSON against a public key.
///
/// Returns `"true"` or `"false"`.
#[cfg(feature = "wasm")]
#[wasm_bindgen::prelude::wasm_bindgen]
pub fn a2a_verify(msg_json: &str, pk_hex: &str) -> bool {
    let Ok(msg): Result<A2AMessage, _> = serde_json::from_str(msg_json) else {
        return false;
    };
    let Ok(pk_bytes) = hex::decode(pk_hex) else {
        return false;
    };
    let Ok(pk_arr): Result<[u8; 32], _> = pk_bytes.try_into() else {
        return false;
    };
    msg.verify(&pk_arr)
}

#[cfg(feature = "wasm")]
fn decode_b64_simple(input: &str) -> Result<Vec<u8>, String> {
    let input = input.trim_end_matches('=');
    let mut out = Vec::with_capacity(input.len() * 3 / 4);
    let mut buf = 0u32;
    let mut bits = 0u8;
    for ch in input.bytes() {
        let v = match ch {
            b'A'..=b'Z' => ch - b'A',
            b'a'..=b'z' => ch - b'a' + 26,
            b'0'..=b'9' => ch - b'0' + 52,
            b'+' => 62,
            b'/' => 63,
            _ => return Err(format!("invalid base64 char: {ch}")),
        } as u32;
        buf = (buf << 6) | v;
        bits += 6;
        if bits >= 8 {
            bits -= 8;
            out.push((buf >> bits) as u8);
            buf &= (1 << bits) - 1;
        }
    }
    Ok(out)
}

// ── Tests ─────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;
    use crate::identity::keygen;

    #[test]
    fn test_a2a_build_sign_verify_roundtrip() {
        let (sk, pk) = keygen();
        let mut msg = A2AMessage::build(
            "agent-alice",
            "agent-bob",
            "aabbccdd00112233aabbccdd00112233",
            1_700_000_000_000,
            "application/json",
            br#"{"action":"ping"}"#.to_vec(),
        );
        msg.sign(&sk).expect("sign must succeed");
        assert!(!msg.signature.is_empty(), "signature must be set");
        assert!(msg.verify(&pk), "valid signature must verify");
    }

    #[test]
    fn test_a2a_tampered_payload_fails() {
        let (sk, pk) = keygen();
        let mut msg = A2AMessage::build(
            "agent-alice",
            "agent-bob",
            "aabbccdd00112233aabbccdd00112233",
            1_700_000_000_000,
            "application/json",
            b"original payload".to_vec(),
        );
        msg.sign(&sk).expect("sign must succeed");
        // Tamper with payload
        msg.payload = b"tampered payload".to_vec();
        assert!(!msg.verify(&pk), "tampered payload must not verify");
    }

    #[test]
    fn test_a2a_wrong_key_fails() {
        let (sk_a, _pk_a) = keygen();
        let (_sk_b, pk_b) = keygen();
        let mut msg = A2AMessage::build(
            "agent-alice",
            "agent-bob",
            "deadbeef00112233deadbeef00112233",
            1_700_000_000_001,
            "text/plain",
            b"hello".to_vec(),
        );
        msg.sign(&sk_a).expect("sign with key A");
        assert!(
            !msg.verify(&pk_b),
            "signature from key-A must not verify under key-B"
        );
    }

    #[test]
    fn test_a2a_canonical_bytes_deterministic() {
        let msg = A2AMessage {
            from: "alice".to_string(),
            to: "bob".to_string(),
            nonce: "nonce123".to_string(),
            timestamp_ms: 1_700_000_000,
            signature: "".to_string(),
            content_type: "application/json".to_string(),
            payload: b"{}".to_vec(),
        };
        let b1 = msg.canonical_bytes();
        let b2 = msg.canonical_bytes();
        assert_eq!(b1, b2, "canonical_bytes must be deterministic");
    }

    #[test]
    fn test_a2a_canonical_bytes_format() {
        let msg = A2AMessage {
            from: "alice".to_string(),
            to: "bob".to_string(),
            nonce: "nonce123".to_string(),
            timestamp_ms: 1_700_000_000,
            signature: "".to_string(),
            content_type: "text/plain".to_string(),
            payload: b"hello".to_vec(),
        };
        let bytes = msg.canonical_bytes();
        let s = String::from_utf8(bytes).unwrap();
        let parts: Vec<&str> = s.splitn(6, '\n').collect();
        assert_eq!(parts[0], "alice");
        assert_eq!(parts[1], "bob");
        assert_eq!(parts[2], "nonce123");
        assert_eq!(parts[3], "1700000000");
        assert_eq!(parts[4], "text/plain");
        // parts[5] is sha256("hello") hex
        assert_eq!(
            parts[5],
            "2cf24dba5fb0a30e26e83b2ac5b9e29e1b161e5c1fa7425e73043362938b9824"
        );
    }

    #[test]
    fn test_a2a_serde_roundtrip() {
        let (sk, pk) = keygen();
        let mut msg = A2AMessage::build(
            "agent-1",
            "agent-2",
            "0011223344556677",
            42_000,
            "application/json",
            br#"{"key":"value"}"#.to_vec(),
        );
        msg.sign(&sk).expect("sign must succeed");

        let json = serde_json::to_string(&msg).expect("serialize");
        let parsed: A2AMessage = serde_json::from_str(&json).expect("deserialize");

        assert_eq!(parsed.from, "agent-1");
        assert_eq!(parsed.to, "agent-2");
        assert!(parsed.verify(&pk), "deserialized message must verify");
    }
}

//! Byzantine Fault Tolerant (BFT) consensus primitives for LLMtxt.
//!
//! # Background
//!
//! A system of `n` validators can tolerate `f` Byzantine (malicious or faulty)
//! validators if and only if `n >= 3f + 1`. The minimum quorum required to
//! reach consensus is `2f + 1` (a "supermajority").
//!
//! This module implements:
//! * [`bft_quorum`] — compute the minimum quorum for a given `n` and `f`.
//! * [`bft_max_faults`] — compute the maximum tolerable faults for `n`.
//! * [`bft_check`] — check whether a given vote count satisfies the quorum.
//! * [`hash_chain_extend`] — extend a tamper-evident hash chain with a new event.
//! * [`verify_chain`] — verify the integrity of an entire chain of events.

use sha2::{Digest, Sha256};

// ── BFT Quorum Math ──────────────────────────────────────────────

/// Compute the minimum quorum (number of votes) needed for BFT consensus.
///
/// Formula: `quorum = 2f + 1` where `f` is the maximum number of Byzantine faults.
///
/// # Arguments
/// * `_n` — total number of validators (informational; used for validation)
/// * `f`  — maximum number of Byzantine faults to tolerate
///
/// # Returns
/// The minimum number of approvals required: `2f + 1`.
///
/// # Panics
/// Does not panic. Returns 1 when `f == 0`.
///
/// # Example
/// ```
/// use llmtxt_core::bft::bft_quorum;
/// assert_eq!(bft_quorum(3, 1), 3); // 2*1+1 = 3 out of 3 validators
/// assert_eq!(bft_quorum(7, 2), 5); // 2*2+1 = 5 out of 7 validators
/// assert_eq!(bft_quorum(1, 0), 1); // 2*0+1 = 1 (no Byzantine tolerance)
/// ```
pub fn bft_quorum(_n: u32, f: u32) -> u32 {
    2 * f + 1
}

/// Compute the maximum number of Byzantine faults `n` validators can tolerate.
///
/// Formula: `f = (n - 1) / 3` (integer division).
///
/// # Example
/// ```
/// use llmtxt_core::bft::bft_max_faults;
/// assert_eq!(bft_max_faults(3), 0); // 3 validators: f=0 (need 4 for f=1)
/// assert_eq!(bft_max_faults(4), 1); // 4 validators: f=1
/// assert_eq!(bft_max_faults(7), 2); // 7 validators: f=2
/// ```
pub fn bft_max_faults(n: u32) -> u32 {
    if n == 0 {
        return 0;
    }
    (n - 1) / 3
}

/// Check whether `votes` satisfies the BFT quorum for fault tolerance `f`.
///
/// Returns `true` when `votes >= 2f + 1`.
///
/// # Example
/// ```
/// use llmtxt_core::bft::bft_check;
/// assert!(bft_check(3, 1));  // 3 >= 2*1+1: quorum reached
/// assert!(!bft_check(2, 1)); // 2 < 3: quorum not reached
/// ```
pub fn bft_check(votes: u32, f: u32) -> bool {
    votes >= bft_quorum(0, f)
}

// ── Hash Chain ───────────────────────────────────────────────────

/// A single event in a tamper-evident hash chain.
///
/// Each event records the hash of the previous event (or a sentinel for the
/// first event) so that any tampering with a stored event is detectable by
/// recomputing the chain.
#[derive(Debug, Clone)]
pub struct ChainedEvent {
    /// SHA-256 of the preceding event's hash + this event's bytes.
    /// For the first event in a chain, this is `SHA-256(event_bytes)`.
    pub chain_hash: [u8; 32],
    /// The raw event payload (JSON, binary, etc.) — content is opaque.
    pub event_bytes: Vec<u8>,
    /// Hash of the previous event's `chain_hash`, or `[0u8; 32]` for first.
    pub prev_hash: [u8; 32],
}

/// Extend a tamper-evident hash chain with a new event.
///
/// Computes: `chain_hash = SHA-256(prev_hash || event_bytes)`.
///
/// # Arguments
/// * `prev_hash`   — 32-byte hash of the previous event (use `[0u8; 32]` for the first event)
/// * `event_bytes` — raw event payload bytes
///
/// # Returns
/// 32-byte chain hash for the new event.
///
/// # Example
/// ```
/// use llmtxt_core::bft::hash_chain_extend;
/// let genesis_prev = [0u8; 32];
/// let h1 = hash_chain_extend(&genesis_prev, b"first event");
/// let h2 = hash_chain_extend(&h1, b"second event");
/// assert_ne!(h1, h2);
/// assert_ne!(h2, [0u8; 32]);
/// ```
pub fn hash_chain_extend(prev_hash: &[u8; 32], event_bytes: &[u8]) -> [u8; 32] {
    let mut hasher = Sha256::new();
    hasher.update(prev_hash);
    hasher.update(event_bytes);
    hasher.finalize().into()
}

/// Verify the integrity of a chain of events.
///
/// Recomputes each event's `chain_hash` from its `prev_hash` and `event_bytes`,
/// comparing against the stored `chain_hash`. Returns `false` as soon as a
/// mismatch is found.
///
/// The first event's `prev_hash` should be `[0u8; 32]` (the genesis sentinel).
///
/// # Returns
/// `true` if the entire chain is intact, `false` if any event was tampered with.
///
/// # Example
/// ```
/// use llmtxt_core::bft::{ChainedEvent, hash_chain_extend, verify_chain};
///
/// let prev = [0u8; 32];
/// let bytes1 = b"event one".to_vec();
/// let h1 = hash_chain_extend(&prev, &bytes1);
/// let bytes2 = b"event two".to_vec();
/// let h2 = hash_chain_extend(&h1, &bytes2);
///
/// let chain = vec![
///     ChainedEvent { chain_hash: h1, event_bytes: bytes1, prev_hash: prev },
///     ChainedEvent { chain_hash: h2, event_bytes: bytes2.clone(), prev_hash: h1 },
/// ];
/// assert!(verify_chain(&chain));
///
/// // Tamper with the second event
/// let mut bad_chain = chain.clone();
/// bad_chain[1].event_bytes = b"TAMPERED".to_vec();
/// assert!(!verify_chain(&bad_chain));
/// ```
pub fn verify_chain(events: &[ChainedEvent]) -> bool {
    for event in events {
        let expected = hash_chain_extend(&event.prev_hash, &event.event_bytes);
        if expected != event.chain_hash {
            return false;
        }
    }
    true
}

// ── WASM exports ─────────────────────────────────────────────────

/// WASM: compute BFT quorum for fault count `f`.
///
/// Returns `2f + 1` as a u32.
#[cfg(feature = "wasm")]
#[wasm_bindgen::prelude::wasm_bindgen]
pub fn bft_quorum_wasm(n: u32, f: u32) -> u32 {
    bft_quorum(n, f)
}

/// WASM: compute hash chain extension.
///
/// `prev_hash_hex` — 64-char lowercase hex of the 32-byte previous hash.
/// `event_json`    — UTF-8 event payload string.
///
/// Returns 64-char lowercase hex of the new chain hash, or `{"error":"..."}`.
#[cfg(feature = "wasm")]
#[wasm_bindgen::prelude::wasm_bindgen]
pub fn hash_chain_extend_wasm(prev_hash_hex: &str, event_json: &str) -> String {
    let Ok(prev_bytes) = hex::decode(prev_hash_hex) else {
        return r#"{"error":"invalid prev_hash_hex"}"#.to_string();
    };
    let Ok(prev_arr): Result<[u8; 32], _> = prev_bytes.try_into() else {
        return r#"{"error":"prev_hash must be 32 bytes"}"#.to_string();
    };
    let hash = hash_chain_extend(&prev_arr, event_json.as_bytes());
    hex::encode(hash)
}

// ── Tests ─────────────────────────────────────────────────────────

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn test_bft_quorum_basic() {
        // f=0: quorum=1 (trivial consensus, no Byzantine tolerance)
        assert_eq!(bft_quorum(1, 0), 1);
        // f=1: quorum=3 (classic 3f+1=4, but quorum is 2f+1=3)
        assert_eq!(bft_quorum(4, 1), 3);
        // f=2: quorum=5
        assert_eq!(bft_quorum(7, 2), 5);
        // f=3: quorum=7
        assert_eq!(bft_quorum(10, 3), 7);
    }

    #[test]
    fn test_bft_max_faults() {
        assert_eq!(bft_max_faults(0), 0);
        assert_eq!(bft_max_faults(1), 0);
        assert_eq!(bft_max_faults(3), 0); // 3 needs f=1 → need n=4
        assert_eq!(bft_max_faults(4), 1);
        assert_eq!(bft_max_faults(7), 2);
        assert_eq!(bft_max_faults(10), 3);
    }

    #[test]
    fn test_bft_check() {
        // f=1: quorum=3
        assert!(bft_check(3, 1));
        assert!(bft_check(4, 1));
        assert!(!bft_check(2, 1));
        assert!(!bft_check(1, 1));

        // f=2: quorum=5
        assert!(bft_check(5, 2));
        assert!(!bft_check(4, 2));

        // f=0: quorum=1 (anyone's vote counts)
        assert!(bft_check(1, 0));
        assert!(!bft_check(0, 0));
    }

    #[test]
    fn test_hash_chain_extend_deterministic() {
        let prev = [0u8; 32];
        let h1 = hash_chain_extend(&prev, b"event one");
        let h2 = hash_chain_extend(&prev, b"event one");
        assert_eq!(h1, h2, "same inputs must produce same hash");
    }

    #[test]
    fn test_hash_chain_extend_unique() {
        let prev = [0u8; 32];
        let h1 = hash_chain_extend(&prev, b"event one");
        let h2 = hash_chain_extend(&prev, b"event two");
        assert_ne!(h1, h2);
    }

    #[test]
    fn test_hash_chain_extend_chaining() {
        let prev = [0u8; 32];
        let h1 = hash_chain_extend(&prev, b"event one");
        let h2 = hash_chain_extend(&h1, b"event two");
        // h2 depends on h1 — changing the order changes the result
        let h2_swapped = hash_chain_extend(&prev, b"event two");
        assert_ne!(h2, h2_swapped);
    }

    #[test]
    fn test_verify_chain_valid() {
        let prev = [0u8; 32];
        let bytes1 = b"approval:agent-1:APPROVED".to_vec();
        let h1 = hash_chain_extend(&prev, &bytes1);
        let bytes2 = b"approval:agent-2:APPROVED".to_vec();
        let h2 = hash_chain_extend(&h1, &bytes2);
        let bytes3 = b"approval:agent-3:APPROVED".to_vec();
        let h3 = hash_chain_extend(&h2, &bytes3);

        let chain = vec![
            ChainedEvent {
                chain_hash: h1,
                event_bytes: bytes1,
                prev_hash: prev,
            },
            ChainedEvent {
                chain_hash: h2,
                event_bytes: bytes2,
                prev_hash: h1,
            },
            ChainedEvent {
                chain_hash: h3,
                event_bytes: bytes3,
                prev_hash: h2,
            },
        ];

        assert!(verify_chain(&chain), "valid chain must verify");
    }

    #[test]
    fn test_verify_chain_tampered_payload() {
        let prev = [0u8; 32];
        let bytes1 = b"approval:agent-1:APPROVED".to_vec();
        let h1 = hash_chain_extend(&prev, &bytes1);

        let mut chain = vec![ChainedEvent {
            chain_hash: h1,
            event_bytes: bytes1,
            prev_hash: prev,
        }];

        // Tamper with the payload bytes
        chain[0].event_bytes = b"approval:agent-1:REJECTED".to_vec();
        assert!(
            !verify_chain(&chain),
            "tampered payload must fail verification"
        );
    }

    #[test]
    fn test_verify_chain_tampered_hash() {
        let prev = [0u8; 32];
        let bytes1 = b"approval:agent-1:APPROVED".to_vec();
        let h1 = hash_chain_extend(&prev, &bytes1);

        let mut chain = vec![ChainedEvent {
            chain_hash: h1,
            event_bytes: bytes1,
            prev_hash: prev,
        }];

        // Tamper with the stored chain hash
        chain[0].chain_hash[0] ^= 0xFF;
        assert!(
            !verify_chain(&chain),
            "tampered chain_hash must fail verification"
        );
    }

    #[test]
    fn test_verify_chain_empty() {
        // Empty chain is trivially valid
        assert!(verify_chain(&[]));
    }

    #[test]
    fn test_bft_adversarial_3honest_2byzantine() {
        // Adversarial scenario: 5 total agents, f=1 (BFT quorum = 3)
        // 3 honest agents vote APPROVED, 2 Byzantine agents vote REJECTED
        // Result: APPROVED wins because 3 >= 2*1+1 = 3
        let f = 1u32;
        let honest_votes = 3u32;
        let byzantine_votes = 2u32;

        // Honest quorum is reached
        assert!(bft_check(honest_votes, f), "honest quorum must be reached");
        // Byzantine faction cannot override (they'd need a quorum too)
        assert!(
            !bft_check(byzantine_votes, f),
            "byzantine faction must NOT reach quorum"
        );
    }

    #[test]
    fn test_bft_default_config_f1_quorum3() {
        // Default config: f=1, quorum=3
        // A document with minApprovals=3 requires 3 distinct approvals
        let f = 1u32;
        let quorum = bft_quorum(0, f);
        assert_eq!(quorum, 3);
        assert!(bft_check(3, f));
        assert!(!bft_check(2, f));
    }

    #[test]
    fn test_hash_chain_10_sequential() {
        // Simulate 10 sequential approval events — verify chain integrity
        let mut prev = [0u8; 32];
        let mut chain = Vec::new();

        for i in 0u32..10 {
            let event_bytes = format!("approval:agent-{i}:APPROVED").into_bytes();
            let chain_hash = hash_chain_extend(&prev, &event_bytes);
            chain.push(ChainedEvent {
                chain_hash,
                event_bytes,
                prev_hash: prev,
            });
            prev = chain_hash;
        }

        assert_eq!(chain.len(), 10);
        assert!(verify_chain(&chain), "10-event chain must verify");

        // Tamper with event 5 — verification must fail
        chain[5].event_bytes = b"TAMPERED".to_vec();
        assert!(!verify_chain(&chain), "tampered event must fail");
    }
}

//! Tier limit evaluation — Single Source of Truth for billing policy.
//!
//! All tier limits and the evaluation function live here. The TypeScript
//! backend imports these through the WASM binding so that limit values
//! are never duplicated across the codebase.
//!
//! # Design invariants
//! - `evaluate_tier_limits` is a pure function: no I/O, no global state.
//! - Same inputs always produce the same output.
//! - `None` in `TierLimits` means "no cap enforced" (Enterprise unlimited fields).

use serde::{Deserialize, Serialize};

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

// ── Tier kinds ───────────────────────────────────────────────────────────────

/// The billing tier a user is subscribed to.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum TierKind {
    Free,
    Pro,
    Enterprise,
}

impl TierKind {
    /// Parse a string (case-insensitive) into a `TierKind`.
    /// Unknown strings default to `Free`.
    pub fn from_tier_str(s: &str) -> Self {
        match s.to_ascii_lowercase().as_str() {
            "pro" => TierKind::Pro,
            "enterprise" => TierKind::Enterprise,
            _ => TierKind::Free,
        }
    }
}

// ── Limits ───────────────────────────────────────────────────────────────────

/// The maximum allowed values for a given tier.
/// `None` means "no cap" (unlimited).
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct TierLimits {
    /// Maximum number of documents owned.
    pub max_documents: Option<u64>,
    /// Maximum bytes per single document (content size).
    pub max_doc_bytes: Option<u64>,
    /// Maximum API calls (all routes) per billing month.
    pub max_api_calls_per_month: Option<u64>,
    /// Maximum CRDT operations per billing month.
    pub max_crdt_ops_per_month: Option<u64>,
    /// Maximum registered agent seats.
    pub max_agent_seats: Option<u64>,
    /// Maximum total storage bytes.
    pub max_storage_bytes: Option<u64>,
}

/// Return the hard limits for a given tier.
///
/// This is the canonical source — all tier checks in the backend
/// call this function (via WASM or native) rather than defining
/// constants locally.
pub fn tier_limits(tier: TierKind) -> TierLimits {
    match tier {
        TierKind::Free => TierLimits {
            max_documents: Some(50),
            max_doc_bytes: Some(500 * 1024), // 500 KB
            max_api_calls_per_month: Some(1_000),
            max_crdt_ops_per_month: Some(500),
            max_agent_seats: Some(3),
            max_storage_bytes: Some(25 * 1024 * 1024), // 25 MB
        },
        TierKind::Pro => TierLimits {
            max_documents: Some(500),
            max_doc_bytes: Some(10 * 1024 * 1024), // 10 MB
            max_api_calls_per_month: Some(50_000),
            max_crdt_ops_per_month: Some(25_000),
            max_agent_seats: Some(25),
            max_storage_bytes: Some(5 * 1024 * 1024 * 1024), // 5 GB
        },
        TierKind::Enterprise => TierLimits {
            max_documents: None,
            max_doc_bytes: Some(100 * 1024 * 1024), // 100 MB per doc
            max_api_calls_per_month: None,
            max_crdt_ops_per_month: None,
            max_agent_seats: None,
            max_storage_bytes: None,
        },
    }
}

// ── Usage snapshot ───────────────────────────────────────────────────────────

/// A point-in-time snapshot of a user's resource consumption.
/// Collected by the backend and passed here for evaluation.
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct UsageSnapshot {
    /// Total documents currently owned by the user.
    pub document_count: u64,
    /// API calls made in the current billing period.
    pub api_calls_this_month: u64,
    /// CRDT operations in the current billing period.
    pub crdt_ops_this_month: u64,
    /// Number of registered agent identities.
    pub agent_seat_count: u64,
    /// Total bytes stored across all documents and blobs.
    pub storage_bytes: u64,
    /// Bytes of the document being written (0 if not a write operation).
    pub current_doc_bytes: u64,
}

// ── Decision ─────────────────────────────────────────────────────────────────

/// Result of evaluating a usage snapshot against tier limits.
#[derive(Debug, Clone, Serialize, Deserialize)]
#[serde(tag = "status", rename_all = "lowercase")]
pub enum TierDecision {
    /// The operation is within limits.
    Allowed,
    /// The operation exceeds a limit. The request MUST be rejected (HTTP 402).
    Blocked {
        /// Which limit was exceeded (matches field name in `TierLimits`).
        limit_type: String,
        /// Current usage value.
        current: u64,
        /// The maximum allowed value.
        limit: u64,
    },
}

// ── Evaluation ───────────────────────────────────────────────────────────────

/// Evaluate whether a usage snapshot is within the limits for a tier.
///
/// Returns `TierDecision::Allowed` when all limits are satisfied,
/// or `TierDecision::Blocked` for the first limit exceeded (checked in
/// priority order: documents → doc_bytes → api_calls → crdt_ops →
/// agent_seats → storage).
///
/// # Invariants
/// - Pure function — no I/O or global state.
/// - Deterministic — same inputs always yield the same output.
pub fn evaluate_tier_limits(usage: &UsageSnapshot, tier: TierKind) -> TierDecision {
    let limits = tier_limits(tier);

    // 1. Document count
    if let Some(max) = limits.max_documents
        && usage.document_count >= max
    {
        return TierDecision::Blocked {
            limit_type: "max_documents".into(),
            current: usage.document_count,
            limit: max,
        };
    }

    // 2. Per-document size (only meaningful for write events)
    if usage.current_doc_bytes > 0
        && let Some(max) = limits.max_doc_bytes
        && usage.current_doc_bytes > max
    {
        return TierDecision::Blocked {
            limit_type: "max_doc_bytes".into(),
            current: usage.current_doc_bytes,
            limit: max,
        };
    }

    // 3. Monthly API calls
    if let Some(max) = limits.max_api_calls_per_month
        && usage.api_calls_this_month >= max
    {
        return TierDecision::Blocked {
            limit_type: "max_api_calls_per_month".into(),
            current: usage.api_calls_this_month,
            limit: max,
        };
    }

    // 4. Monthly CRDT operations
    if let Some(max) = limits.max_crdt_ops_per_month
        && usage.crdt_ops_this_month >= max
    {
        return TierDecision::Blocked {
            limit_type: "max_crdt_ops_per_month".into(),
            current: usage.crdt_ops_this_month,
            limit: max,
        };
    }

    // 5. Agent seats
    if let Some(max) = limits.max_agent_seats
        && usage.agent_seat_count >= max
    {
        return TierDecision::Blocked {
            limit_type: "max_agent_seats".into(),
            current: usage.agent_seat_count,
            limit: max,
        };
    }

    // 6. Total storage
    if let Some(max) = limits.max_storage_bytes
        && usage.storage_bytes >= max
    {
        return TierDecision::Blocked {
            limit_type: "max_storage_bytes".into(),
            current: usage.storage_bytes,
            limit: max,
        };
    }

    TierDecision::Allowed
}

// ── WASM bindings ────────────────────────────────────────────────────────────

/// WASM binding: evaluate tier limits from JSON-serialised inputs.
///
/// `usage_json` — JSON of `UsageSnapshot`.
/// `tier_str` — `"free"` | `"pro"` | `"enterprise"` (case-insensitive).
///
/// Returns JSON of `TierDecision`, or `{"error":"..."}` on parse failure.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn evaluate_tier_limits_wasm(usage_json: &str, tier_str: &str) -> String {
    let usage: UsageSnapshot = match serde_json::from_str(usage_json) {
        Ok(u) => u,
        Err(e) => return format!(r#"{{"error":{}}}"#, serde_json::json!(e.to_string())),
    };
    let tier = TierKind::from_tier_str(tier_str);
    let decision = evaluate_tier_limits(&usage, tier);
    match serde_json::to_string(&decision) {
        Ok(json) => json,
        Err(e) => format!(r#"{{"error":{}}}"#, serde_json::json!(e.to_string())),
    }
}

/// WASM binding: return tier limits as JSON.
///
/// `tier_str` — `"free"` | `"pro"` | `"enterprise"` (case-insensitive).
///
/// Returns JSON of `TierLimits`, or `{"error":"..."}` on serialization failure.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn get_tier_limits_wasm(tier_str: &str) -> String {
    let tier = TierKind::from_tier_str(tier_str);
    let limits = tier_limits(tier);
    match serde_json::to_string(&limits) {
        Ok(json) => json,
        Err(e) => format!(r#"{{"error":{}}}"#, serde_json::json!(e.to_string())),
    }
}

