        let contents: Vec<&str> = insertion_lines.iter().map(|l| l.content.as_str()).collect();
        assert!(contents.contains(&"# New Section"));
        assert!(contents.contains(&"Middle content."));
    }
}

//! LCS-aligned multi-way diff helpers.
//!
//! Internal implementation module for [`crate::multi_way_diff_native`].
//! All types and functions here are private to the crate.

use crate::diff::{MultiDiffLine, MultiDiffStats, MultiDiffVariant, structured_diff_native};

// ── Internal grid types ────────────────────────────────────────

/// What a single version contributes at one aligned grid slot.
#[derive(Debug, Clone)]
pub(crate) enum SlotContent {
    /// The version has this line at the aligned base position (context).
    Present(String),
    /// The version deleted the base line at this position.
    Absent,
    /// This slot is an insertion row — the version supplies this content here.
    Inserted(String),
    /// This slot is an insertion row but this version has no line here.
    NotInserted,
}

/// One row in the aligned grid.
#[derive(Debug, Clone)]
pub(crate) struct AlignedRow {
    /// True when this row comes from a base line; false for insertion rows.
    pub is_base_line: bool,
    /// Per-version content. Length == `version_count`.
    pub slots: Vec<SlotContent>,
}

/// Per-version LCS alignment of one additional version against the base.
pub(crate) struct VersionAlignment {
    /// 1-indexed by base line number. `None` means the version removed that line.
    pub base_line_action: Vec<Option<String>>,
    /// `insertions_after[i]` holds lines this version inserts after base line `i`
    /// (index 0 = before base line 1).
    pub insertions_after: Vec<Vec<String>>,
}

// ── Alignment helpers ──────────────────────────────────────────

/// Align one additional version against `base` using [`structured_diff_native`].
///
/// Returns a [`VersionAlignment`] describing which base lines the version kept
/// (context), replaced with new content (present with different text), deleted
/// (absent), and which entirely new lines it inserted between base lines.
///
/// **Replacement detection**: in the LCS diff, a "removed" entry immediately
/// followed by one or more "added" entries (before the next "context" or
/// "removed") is treated as a replacement: the first "added" becomes the
/// version's content for that base-line slot, and any remaining "added" entries
/// are insertions appended after it.  This avoids falsely reporting divergent
/// content as absent-plus-insertion, which would inflate insertion counts and
/// deflate consensus percentages.
pub(crate) fn align_version(base: &str, version_text: &str, n_base: usize) -> VersionAlignment {
    let diff = structured_diff_native(base, version_text);

    // Slot 0 is unused (1-indexed). Default to None (= absent/deleted).
    let mut base_line_action: Vec<Option<String>> = vec![None; n_base + 1];
    // insertions_after[0] = before base line 1; insertions_after[i] = after line i.
    let mut insertions_after: Vec<Vec<String>> = vec![Vec::new(); n_base + 1];

    // `cursor` is the last base line we have committed.
    // `pending_removal` holds a base line index that was removed and may be
    // replaced by the immediately following "added" entry.
    let mut cursor: usize = 0;
    let mut pending_removal: Option<usize> = None;

    for entry in &diff.lines {
        match entry.line_type.as_str() {
            "context" => {
                // Any pending removal is a pure deletion — leave its slot as None.
                pending_removal = None;
                if let Some(base_idx) = entry.old_line {
                    let idx = base_idx as usize;
                    base_line_action[idx] = Some(entry.content.clone());
                    cursor = idx;
                }
            }
            "removed" => {
                // Flush any previous pending removal as a pure deletion.
                if let Some(prev) = pending_removal.take() {
                    // base_line_action[prev] stays None; cursor stays at prev.
                    cursor = prev;
                }
                if let Some(base_idx) = entry.old_line {
                    pending_removal = Some(base_idx as usize);
                }
            }
            "added" => {
                if let Some(removed_idx) = pending_removal.take() {
                    // First "added" after a "removed" = replacement of that base line.
                    base_line_action[removed_idx] = Some(entry.content.clone());
                    cursor = removed_idx;
                } else {
                    // Pure insertion after `cursor`.
                    insertions_after[cursor].push(entry.content.clone());
                }
            }
            _ => {}
        }
    }
    // Flush any trailing pending removal.
    if let Some(prev) = pending_removal {
        cursor = prev;
        let _ = cursor; // suppress unused-variable warning
    }

    VersionAlignment {
        base_line_action,
        insertions_after,
    }
}

/// Emit insertion rows for lines added by any version after `after_base_line`.
///
/// Insertions from each version are interleaved in version order at each depth
/// level (first line inserted by each version, then second, etc.).
pub(crate) fn emit_insertions_after(
    grid: &mut Vec<AlignedRow>,
    alignments: &[VersionAlignment],
    version_count: usize,
    after_base_line: usize,
) {
    let lists: Vec<&Vec<String>> = alignments
        .iter()
        .map(|a| &a.insertions_after[after_base_line])
        .collect();

    let max_depth = lists.iter().map(|l| l.len()).max().unwrap_or(0);
    if max_depth == 0 {
        return;
    }

    for depth in 0..max_depth {
        for (vi, list) in lists.iter().enumerate() {
            if depth >= list.len() {
                continue;
            }
            // One insertion row per version per depth.  Slot 0 = base (never inserts).
            let mut slots: Vec<SlotContent> = Vec::with_capacity(version_count);
            slots.push(SlotContent::NotInserted);
            for vi2 in 0..lists.len() {
                if vi2 == vi {
                    slots.push(SlotContent::Inserted(list[depth].clone()));
                } else {
                    slots.push(SlotContent::NotInserted);
                }
            }
            grid.push(AlignedRow {
                is_base_line: false,
                slots,
            });
        }
    }
}

/// Build the aligned grid from base lines and per-version alignments.
///
/// Each base line becomes an anchor row; insertion rows for version-added lines
/// are interleaved immediately after the base line they follow.
pub(crate) fn build_aligned_grid(
    base_lines: &[&str],
    alignments: &[VersionAlignment],
    version_count: usize,
) -> Vec<AlignedRow> {
    let n_base = base_lines.len();
    let mut grid: Vec<AlignedRow> = Vec::new();

    // Insertions before base line 1.
    emit_insertions_after(&mut grid, alignments, version_count, 0);

    for base_line_idx in 1..=n_base {
        let base_content = base_lines[base_line_idx - 1].to_string();
        let mut slots: Vec<SlotContent> = Vec::with_capacity(version_count);
        // Slot 0 = base — always present.
        slots.push(SlotContent::Present(base_content));
        for alignment in alignments {
            match &alignment.base_line_action[base_line_idx] {
                Some(c) => slots.push(SlotContent::Present(c.clone())),
                None => slots.push(SlotContent::Absent),
            }
        }
        grid.push(AlignedRow {
            is_base_line: true,
            slots,
        });

        emit_insertions_after(&mut grid, alignments, version_count, base_line_idx);
    }

    grid
}

/// Convert the aligned grid into [`MultiDiffLine`] entries and aggregate stats.
///
/// Consensus percentage is computed over base-line rows only.  Insertion rows
/// are version-specific additions and do not count as disagreements.
pub(crate) fn score_grid(
    grid: &[AlignedRow],
    version_count: usize,
) -> (Vec<MultiDiffLine>, MultiDiffStats) {
    // Absent slots use a sentinel so they compare unequal to real content.
    const ABSENT: &str = "\x00__ABSENT__\x00";

    let mut result_lines: Vec<MultiDiffLine> = Vec::with_capacity(grid.len());
    let mut consensus_count = 0usize;
    let mut divergent_count = 0usize;
    let mut insertion_count = 0usize;

    for (row_idx, row) in grid.iter().enumerate() {
        let line_number = row_idx + 1;

        if !row.is_base_line {
            // Find the single version that contributed this insertion.
            let mut content = String::new();
            let mut inserting_vi = 0usize;
            for (vi, slot) in row.slots.iter().enumerate() {
                if let SlotContent::Inserted(c) = slot {
                    content = c.clone();
                    inserting_vi = vi;
                    break;
                }
            }
            insertion_count += 1;
            result_lines.push(MultiDiffLine {
                line_number,
                line_type: "insertion".to_string(),
                content: content.clone(),
                agreement: 1,
                total: version_count,
                variants: vec![MultiDiffVariant {
                    version_index: inserting_vi,
                    content,
                }],
            });
            continue;
        }

        // Base-line row: find the plurality content.
        let contents: Vec<&str> = row
            .slots
            .iter()
            .map(|s| match s {
                SlotContent::Present(c) => c.as_str(),
                _ => ABSENT,
            })
            .collect();

        let mut best: &str = contents[0];
        let mut best_n = 0usize;
        for candidate in &contents {
            let n = contents.iter().filter(|c| *c == candidate).count();
            if n > best_n {
                best_n = n;
                best = candidate;
            }
        }

        if best_n == version_count {
            consensus_count += 1;
            result_lines.push(MultiDiffLine {
                line_number,
                line_type: "consensus".to_string(),
                content: best.to_string(),
                agreement: version_count,
                total: version_count,
                variants: vec![],
            });
        } else {
            divergent_count += 1;
            let variants: Vec<MultiDiffVariant> = row
                .slots
                .iter()
                .enumerate()
                .map(|(vi, slot)| {
                    let c = match slot {
                        SlotContent::Present(s) => s.clone(),
                        _ => String::new(),
                    };
                    MultiDiffVariant {
                        version_index: vi,
                        content: c,
                    }
                })
                .collect();
            result_lines.push(MultiDiffLine {
                line_number,
                line_type: "divergent".to_string(),
                content: if best == ABSENT {
                    String::new()
                } else {
                    best.to_string()
                },
                agreement: best_n,
                total: version_count,
                variants,
            });
        }
    }

    let base_row_count = consensus_count + divergent_count;
    let consensus_percentage = if base_row_count == 0 {
        100.0
    } else {
        let pct = (consensus_count as f64 / base_row_count as f64) * 100.0;
        (pct * 10.0).round() / 10.0
    };

    let stats = MultiDiffStats {
        total_lines: base_row_count + insertion_count,
        consensus_lines: consensus_count,
        divergent_lines: divergent_count,
        consensus_percentage,
    };

    (result_lines, stats)
}

//! Code section parsing for progressive disclosure.

use crate::calculate_tokens;
use crate::disclosure::types::Section;

/// Pattern types that indicate the start of a code section.
struct Pattern {
    prefix: &'static str,
    section_type: &'static str,
}

const PATTERNS: &[Pattern] = &[
    Pattern {
        prefix: "export async function ",
        section_type: "function",
    },
    Pattern {
        prefix: "async function ",
        section_type: "function",
    },
    Pattern {
        prefix: "export function ",
        section_type: "function",
    },
    Pattern {
        prefix: "function ",
        section_type: "function",
    },
    Pattern {
        prefix: "export class ",
        section_type: "class",
    },
    Pattern {
        prefix: "class ",
        section_type: "class",
    },
    Pattern {
        prefix: "export const ",
        section_type: "function",
    },
    Pattern {
        prefix: "const ",
        section_type: "function",
    },
    Pattern {
        prefix: "export let ",
        section_type: "function",
    },
    Pattern {
        prefix: "let ",
        section_type: "function",
    },
    Pattern {
        prefix: "export var ",
        section_type: "function",
    },
    Pattern {
        prefix: "var ",
        section_type: "function",
    },
    Pattern {
        prefix: "def ",
        section_type: "function",
    },
    Pattern {
        prefix: "pub fn ",
        section_type: "function",
    },
    Pattern {
        prefix: "fn ",
        section_type: "function",
    },
    Pattern {
        prefix: "func ",
        section_type: "function",
    },
];

/// Check whether a line matches a function/class pattern and return the symbol name.
fn match_pattern(line: &str) -> Option<(&'static str, String)> {
    for pat in PATTERNS {
        if let Some(rest) = line.strip_prefix(pat.prefix) {
            // Extract identifier (stop at whitespace, '(', '<', '=', '{')
            let name: String = rest
                .chars()
                .take_while(|&c| c.is_alphanumeric() || c == '_')
                .collect();
            if !name.is_empty() {
                return Some((pat.section_type, name));
            }
        }
    }
    None
}

/// Parse code lines into sections based on function/class declarations.
pub fn parse_code_sections(lines: &[&str]) -> Vec<Section> {
    let mut sections: Vec<Section> = Vec::new();

    for (i, line) in lines.iter().enumerate() {
        if let Some((section_type, name)) = match_pattern(line.trim_start()) {
            // Find end of this section (next pattern match)
            let mut end_line = lines.len();
            for (j, next_line) in lines.iter().enumerate().skip(i + 1) {
                if match_pattern(next_line.trim_start()).is_some() {
                    end_line = j;
                    break;
                }
            }
            let section_content = lines[i..end_line].join("\n");
            sections.push(Section {
                title: name,
                depth: 0,
                start_line: i + 1,
                end_line,
                token_count: calculate_tokens(&section_content),
                section_type: section_type.to_string(),
            });
        }
    }

    sections
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn parse_function_declaration() {
        let lines = vec!["function hello() {", "  return 42;", "}"];
        let sections = parse_code_sections(&lines);
        assert_eq!(sections.len(), 1);
        assert_eq!(sections[0].title, "hello");
        assert_eq!(sections[0].section_type, "function");
    }

    #[test]
    fn parse_class_declaration() {
        let lines = vec!["class MyClass {", "  constructor() {}", "}"];
        let sections = parse_code_sections(&lines);
        assert_eq!(sections.len(), 1);
        assert_eq!(sections[0].title, "MyClass");
        assert_eq!(sections[0].section_type, "class");
    }

    #[test]
    fn parse_export_function() {
        let lines = vec!["export function foo() {", "}"];
        let sections = parse_code_sections(&lines);
        assert_eq!(sections.len(), 1);
        assert_eq!(sections[0].title, "foo");
    }
}

//! JSON section parsing for progressive disclosure.

use crate::calculate_tokens;
use crate::disclosure::types::{JsonKey, Section};

fn truncate(s: &str, max_len: usize) -> String {
    if s.len() <= max_len {
        s.to_string()
    } else {
        // Find char boundary
        let mut end = max_len.saturating_sub(3);
        while end > 0 && !s.is_char_boundary(end) {
            end -= 1;
        }
        format!("{}...", &s[..end])
    }
}

fn escape_regex_chars(s: &str) -> String {
    let special = [
        '\\', '.', '+', '*', '?', '^', '$', '{', '}', '(', ')', '|', '[', ']',
    ];
    let mut result = String::with_capacity(s.len() * 2);
    for c in s.chars() {
        if special.contains(&c) {
            result.push('\\');
        }
        result.push(c);
    }
    result
}

fn get_json_type(value: &serde_json::Value) -> String {
    match value {
        serde_json::Value::Null => "null".to_string(),
        serde_json::Value::Array(a) => format!("array[{}]", a.len()),
        serde_json::Value::Object(o) => format!("object{{{}}}", o.len()),
        serde_json::Value::String(_) => "string".to_string(),
        serde_json::Value::Number(_) => "number".to_string(),
        serde_json::Value::Bool(_) => "boolean".to_string(),
    }
}

/// Extract top-level JSON keys with type info and previews.
pub fn extract_json_keys(content: &str) -> Vec<JsonKey> {
    let parsed: serde_json::Value = match serde_json::from_str(content) {
        Ok(v) => v,
        Err(_) => return vec![],
    };

    match &parsed {
        serde_json::Value::Object(obj) => obj
            .iter()
            .map(|(key, value)| JsonKey {
                key: key.clone(),
                key_type: get_json_type(value),
                preview: truncate(&serde_json::to_string(value).unwrap_or_default(), 80),
            })
            .collect(),
        serde_json::Value::Array(arr) => {
            let preview = arr.first().map_or("[]".to_string(), |v| {
                truncate(&serde_json::to_string(v).unwrap_or_default(), 80)
            });
            vec![JsonKey {
                key: "(array)".to_string(),
                key_type: format!("array[{}]", arr.len()),
                preview,
            }]
        }
        _ => vec![],
    }
}

/// Parse JSON content into sections (one per top-level key or array).
pub fn parse_json_sections(content: &str, lines: &[&str]) -> Vec<Section> {
    let mut sections: Vec<Section> = Vec::new();

    let parsed: serde_json::Value = match serde_json::from_str(content) {
        Ok(v) => v,
        Err(_) => {
            // Fallback: regex-based parse for malformed JSON
            return parse_json_sections_regex(lines);
        }
    };

    match &parsed {
        serde_json::Value::Array(arr) => {
            sections.push(Section {
                title: format!("array[{}]", arr.len()),
                depth: 0,
                start_line: 1,
                end_line: lines.len(),
                token_count: calculate_tokens(content),
                section_type: "json-key".to_string(),
            });
        }
        serde_json::Value::Object(obj) => {
            let keys: Vec<&str> = obj.keys().map(String::as_str).collect();

            for (ki, key) in keys.iter().enumerate() {
                let escaped = escape_regex_chars(key);
                let pattern = format!("\"{}\"", escaped);

                // Find first line that contains `"key":`
                let line_idx = lines
                    .iter()
                    .position(|l| l.contains(&format!("{pattern}:")));

                if let Some(li) = line_idx {
                    // Find start of next top-level key
                    let end_line = if ki + 1 < keys.len() {
                        let next_key = keys[ki + 1];
                        let next_pattern = format!("\"{}\":", escape_regex_chars(next_key));
                        lines
                            .iter()
                            .enumerate()
                            .skip(li + 1)
                            .find(|(_, l)| l.contains(&next_pattern))
                            .map(|(j, _)| j)
                            .unwrap_or(lines.len())
                    } else {
                        lines.len()
                    };

                    let section_content = lines[li..end_line].join("\n");
                    sections.push(Section {
                        title: key.to_string(),
                        depth: 0,
                        start_line: li + 1,
                        end_line,
                        token_count: calculate_tokens(&section_content),
                        section_type: "json-key".to_string(),
                    });
                }
            }
        }
        _ => {}
    }

    sections
}

/// Fallback JSON section parser using simple line scanning.
fn parse_json_sections_regex(lines: &[&str]) -> Vec<Section> {
    let mut sections: Vec<Section> = Vec::new();
    let mut section_start: Option<(String, usize)> = None;

    for (i, line) in lines.iter().enumerate() {
        // Match lines like `  "keyName":`
        if let Some(key_str) = extract_top_level_key(line) {
            if let Some((prev_key, prev_start)) = section_start.take() {
                let section_content = lines[prev_start..i].join("\n");
                sections.push(Section {
                    title: prev_key,
                    depth: 0,
                    start_line: prev_start + 1,
                    end_line: i,
                    token_count: calculate_tokens(&section_content),
                    section_type: "json-key".to_string(),
                });
            }
            section_start = Some((key_str, i));
        }
    }

    // Push last section
    if let Some((key, start)) = section_start {
        let section_content = lines[start..].join("\n");
        sections.push(Section {
            title: key,
            depth: 0,
            start_line: start + 1,
            end_line: lines.len(),
            token_count: calculate_tokens(&section_content),
            section_type: "json-key".to_string(),
        });
    }

    sections
}

/// Extract the top-level key name from a line like `  "keyName": ...`.
fn extract_top_level_key(line: &str) -> Option<String> {
    let trimmed = line.trim_start_matches("  "); // exactly 2 spaces for top-level
    if line.starts_with("  ") && !line.starts_with("   ") && trimmed.starts_with('"') {
        let rest = &trimmed[1..];
        let end = rest.find('"')?;
        let key = rest[..end].to_string();
        if rest[end + 1..].trim_start().starts_with(':') {
            return Some(key);
        }
    }
    None
}

#[cfg(test)]
mod tests {
    use super::*;

    #[test]
    fn json_keys_object() {
        let json = r#"{"name":"Alice","age":30}"#;
        let keys = extract_json_keys(json);
        assert_eq!(keys.len(), 2);
        assert!(keys.iter().any(|k| k.key == "name"));
        assert!(keys.iter().any(|k| k.key == "age"));
    }

    #[test]
    fn json_keys_array() {
        let json = r#"[1,2,3]"#;
        let keys = extract_json_keys(json);
        assert_eq!(keys.len(), 1);
        assert_eq!(keys[0].key, "(array)");
    }

    #[test]
    fn json_sections_array() {
        let json = "[1,2,3]";
        let lines: Vec<&str> = json.lines().collect();
        let sections = parse_json_sections(json, &lines);
        assert_eq!(sections.len(), 1);
        assert!(sections[0].title.starts_with("array["));
    }
}

//! JSONPath resolution helpers for the disclosure module.

/// Execute a JSONPath-style query against a parsed JSON value.
pub fn resolve_path(obj: &serde_json::Value, path: &str) -> Result<serde_json::Value, String> {
    let segments = path.trim_start_matches("$.").trim_start_matches('$');
    if segments.is_empty() {
        return Ok(obj.clone());
    }

    let parts = parse_path_segments(segments);
    let mut current = obj.clone();

    for part in &parts {
        if current.is_null() {
            return Err(format!("Cannot access '{part}' on null"));
        }

        if part == "*" {
            return match &current {
                serde_json::Value::Array(a) => Ok(serde_json::Value::Array(a.clone())),
                serde_json::Value::Object(o) => {
                    Ok(serde_json::Value::Array(o.values().cloned().collect()))
                }
                _ => Err("Wildcard (*) can only be used on arrays or objects".to_string()),
            };
        }

        if let Ok(idx) = part.parse::<usize>() {
            match &current {
                serde_json::Value::Array(a) => {
                    if idx >= a.len() {
                        return Err(format!(
                            "Array index {idx} out of bounds (length: {})",
                            a.len()
                        ));
                    }
                    current = a[idx].clone();
                }
                _ => {
                    return Err(format!("Cannot index '{part}' on non-array"));
                }
            }
        } else {
            match &current {
                serde_json::Value::Object(o) => {
                    current = o
                        .get(part.as_str())
                        .ok_or_else(|| {
                            format!(
                                "Key '{part}' not found. Available keys: {}",
                                o.keys().cloned().collect::<Vec<_>>().join(", ")
                            )
                        })?
                        .clone();
                }
                _ => {
                    return Err(format!(
                        "Cannot access '{part}' on {}",
                        json_type_name(&current)
                    ));
                }
            }
        }
    }

    Ok(current)
}

/// Return a static type name for a JSON value.
pub fn json_type_name(v: &serde_json::Value) -> &'static str {
    match v {
        serde_json::Value::Null => "null",
        serde_json::Value::Bool(_) => "boolean",
        serde_json::Value::Number(_) => "number",
        serde_json::Value::String(_) => "string",
        serde_json::Value::Array(_) => "array",
        serde_json::Value::Object(_) => "object",
    }
}

/// Parse a JSONPath expression into individual path segments.
///
/// Handles dot notation (`a.b.c`) and bracket notation (`a[0].b`).
pub fn parse_path_segments(path: &str) -> Vec<String> {
    let mut segments: Vec<String> = Vec::new();
    let mut current = String::new();
    let chars: Vec<char> = path.chars().collect();
    let mut i = 0;

    while i < chars.len() {
        match chars[i] {
            '.' => {
                if !current.is_empty() {
                    segments.push(current.clone());
                    current.clear();
                }
            }
            '[' => {
                if !current.is_empty() {
                    segments.push(current.clone());
                    current.clear();
                }
                i += 1;
                while i < chars.len() && chars[i] != ']' {
                    current.push(chars[i]);
                    i += 1;
                }
                segments.push(current.clone());
                current.clear();
            }
            c => current.push(c),
        }
        i += 1;
    }

    if !current.is_empty() {
        segments.push(current);
    }
    segments
}

//! Markdown section parsing for progressive disclosure.

use crate::calculate_tokens;
use crate::disclosure::types::{Section, TocEntry};

/// Parse markdown content into sections based on heading levels.
pub fn parse_markdown_sections(lines: &[&str]) -> Vec<Section> {
    let mut sections: Vec<Section> = Vec::new();
    let mut current: Option<(String, u32, usize)> = None; // (title, depth, start_line_1based)

    for (i, line) in lines.iter().enumerate() {
        if let Some(stripped) = line.strip_prefix('#') {
            let level = 1 + stripped.chars().take_while(|&c| c == '#').count();
            if level <= 6 {
                let rest = &stripped[level - 1..];
                if rest.starts_with(' ') || rest.is_empty() {
                    let title = rest.trim().to_string();
                    // Close previous section
                    if let Some((prev_title, prev_depth, prev_start)) = current.take() {
                        let section_lines = lines[prev_start - 1..i].join("\n");
                        sections.push(Section {
                            title: prev_title,
                            depth: prev_depth,
                            start_line: prev_start,
                            end_line: i,
                            token_count: calculate_tokens(&section_lines),
                            section_type: "heading".to_string(),
                        });
                    }
                    current = Some((title, (level - 1) as u32, i + 1));
                    continue;
                }
            }
        }
    }

    // Close last section
    if let Some((title, depth, start)) = current {
        let section_lines = lines[start - 1..].join("\n");
        sections.push(Section {
            title,
            depth,
            start_line: start,
            end_line: lines.len(),
            token_count: calculate_tokens(&section_lines),
            section_type: "heading".to_string(),
        });
    }

    sections
}

/// Extract markdown table of contents from lines.
pub fn extract_markdown_toc(lines: &[&str]) -> Vec<TocEntry> {
    let mut toc = Vec::new();
    for (i, line) in lines.iter().enumerate() {
        if let Some(stripped) = line.strip_prefix('#') {
            let level = 1 + stripped.chars().take_while(|&c| c == '#').count();
            if level <= 6 {
                let rest = &stripped[level - 1..];
                if rest.starts_with(' ') || rest.is_empty() {
                    toc.push(TocEntry {
                        title: rest.trim().to_string(),
                        depth: level as u32,
                        line: i + 1,
                    });
                }
            }
        }
    }
    toc
}

