        let l3 = sha256(b"e3");
        let l4 = sha256(b"e4");

        let h12 = pair_hash(l1, l2);
        let h34 = pair_hash(l3, l4);
        let expected = pair_hash(h12, h34);
        assert_eq!(merkle_root(&[l1, l2, l3, l4]), expected);
    }

