        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let squashed = squash_patches(v0, &patches_json).unwrap();
        let result = apply_patch(v0, &squashed).unwrap();
        assert_eq!(result, v2);
    }

    #[test]
    fn test_reconstruct_version_native() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let patches = vec![create_patch(v0, v1), create_patch(v1, v2)];
        let at_v2 = reconstruct_version_native(v0, &patches, 2).unwrap();
        assert_eq!(at_v2, v2);
    }

    #[test]
    fn test_squash_patches_native() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let patches = vec![create_patch(v0, v1), create_patch(v1, v2)];
        let squashed = squash_patches_native(v0, &patches).unwrap();
        let result = apply_patch(v0, &squashed).unwrap();
        assert_eq!(result, v2);
    }

    #[test]
    fn test_apply_conflicting_patch() {
        let original = "Hello world. This is a test.\n";
        let modified = "Hello beautiful world. This is an awesome test.\n";
        let patch = create_patch(original, modified);

        let result = apply_patch("Completely different text\n", &patch);
        assert!(result.is_err());
    }

    #[test]
    fn test_diff_versions() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nline 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let result_json = diff_versions(v0, &patches_json, 0, 2).unwrap();
        let result: serde_json::Value = serde_json::from_str(&result_json).unwrap();
        assert_eq!(result["fromVersion"], 0);
        assert_eq!(result["toVersion"], 2);
        assert_eq!(result["addedLines"], 2);
        assert_eq!(result["removedLines"], 0);
    }

    #[test]
    fn test_diff_versions_between_non_zero() {
        let v0 = "line 1\n";
        let v1 = "line 1\nline 2\n";
        let v2 = "line 1\nmodified 2\nline 3\n";

        let p1 = create_patch(v0, v1);
        let p2 = create_patch(v1, v2);
        let patches_json = serde_json::to_string(&vec![p1, p2]).unwrap();

        let result_json = diff_versions(v0, &patches_json, 1, 2).unwrap();
        let result: serde_json::Value = serde_json::from_str(&result_json).unwrap();
        assert_eq!(result["fromVersion"], 1);
        assert_eq!(result["toVersion"], 2);
        // "line 2" removed, "modified 2" and "line 3" added
        assert!(result["addedLines"].as_u64().unwrap() > 0);
    }

    #[test]
    fn test_compute_sections_modified_basic() {
        let old = "# Intro\nHello world\n# Details\nSome details\n";
        let new = "# Intro\nHello world\n# Details\nModified details\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["Details"]);
    }

    #[test]
    fn test_compute_sections_modified_new_section() {
        let old = "# Intro\nHello world\n";
        let new = "# Intro\nHello world\n# New Section\nNew content\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["New Section"]);
    }

    #[test]
    fn test_compute_sections_modified_removed_section() {
        let old = "# Intro\nHello world\n# ToRemove\nOld content\n";
        let new = "# Intro\nHello world\n";

        let result = compute_sections_modified_native(old, new);
        assert_eq!(result, vec!["ToRemove"]);
    }

    #[test]
    fn test_compute_sections_modified_no_changes() {
        let content = "# Intro\nHello world\n# Details\nSome details\n";
        let result = compute_sections_modified_native(content, content);
        assert!(result.is_empty());
    }

    #[test]
    fn test_compute_sections_modified_wasm_json() {
        let old = "# A\ntext\n# B\ntext\n";
        let new = "# A\nchanged\n# B\ntext\n";
        let json = compute_sections_modified(old, new);
        let result: Vec<String> = serde_json::from_str(&json).unwrap();
        assert_eq!(result, vec!["A"]);
    }
}

//! Role-Based Access Control primitives for llmtxt documents.
//!
//! Defines the canonical Permission and Role types, plus the
//! ROLE_PERMISSIONS matrix. These are exported from the SDK so all
//! consumers share the same definitions.
//!
//! The Fastify RBAC middleware (`apps/backend/src/middleware/rbac.ts`)
//! imports types from `llmtxt` (the SDK) and uses the JSON-serialised
//! matrix for permission lookups.

#[cfg(feature = "wasm")]
use wasm_bindgen::prelude::*;

use serde::{Deserialize, Serialize};

// ── Permission enum ───────────────────────────────────────────────

/// Fine-grained permission on a document.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum Permission {
    Read,
    Write,
    Delete,
    Manage,
    Approve,
}

impl Permission {
    /// Lowercase string representation, matching the TypeScript union literal.
    pub fn as_str(&self) -> &'static str {
        match self {
            Permission::Read => "read",
            Permission::Write => "write",
            Permission::Delete => "delete",
            Permission::Manage => "manage",
            Permission::Approve => "approve",
        }
    }
}

impl std::fmt::Display for Permission {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.as_str())
    }
}

// ── DocumentRole enum ─────────────────────────────────────────────

/// Role a user can hold on a document.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Hash, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum DocumentRole {
    Owner,
    Editor,
    Viewer,
}

impl DocumentRole {
    pub fn as_str(&self) -> &'static str {
        match self {
            DocumentRole::Owner => "owner",
            DocumentRole::Editor => "editor",
            DocumentRole::Viewer => "viewer",
        }
    }

    /// Return the canonical permission set for this role.
    pub fn permissions(&self) -> &'static [Permission] {
        match self {
            DocumentRole::Owner => &[
                Permission::Read,
                Permission::Write,
                Permission::Delete,
                Permission::Manage,
                Permission::Approve,
            ],
            DocumentRole::Editor => &[Permission::Read, Permission::Write, Permission::Approve],
            DocumentRole::Viewer => &[Permission::Read],
        }
    }
}

impl std::fmt::Display for DocumentRole {
    fn fmt(&self, f: &mut std::fmt::Formatter<'_>) -> std::fmt::Result {
        f.write_str(self.as_str())
    }
}

// ── OrgRole enum ──────────────────────────────────────────────────

/// Role a user holds within an organisation.
#[derive(Debug, Clone, Copy, PartialEq, Eq, Serialize, Deserialize)]
#[serde(rename_all = "lowercase")]
pub enum OrgRole {
    Admin,
    Member,
    Viewer,
}

impl OrgRole {
    /// Map an org-level role to the effective document role.
    /// Org admins get editor-level access; all others get viewer-level.
    pub fn to_document_role(&self) -> DocumentRole {
        match self {
            OrgRole::Admin => DocumentRole::Editor,
            OrgRole::Member | OrgRole::Viewer => DocumentRole::Viewer,
        }
    }
}

// ── WASM helpers ──────────────────────────────────────────────────

/// Return the permissions for a document role as a JSON array of strings.
///
/// Accepts `"owner"`, `"editor"`, or `"viewer"`.
/// Returns `["read","write","delete","manage","approve"]` etc.
/// Returns `"[]"` for unknown roles.
///
/// # Examples (TypeScript via WASM)
/// ```ts
/// import { rolePermissions } from 'llmtxt';
/// rolePermissions('owner');  // '["read","write","delete","manage","approve"]'
/// rolePermissions('viewer'); // '["read"]'
/// ```
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn role_permissions(role: &str) -> String {
    let perms = match role {
        "owner" => DocumentRole::Owner.permissions(),
        "editor" => DocumentRole::Editor.permissions(),
        "viewer" => DocumentRole::Viewer.permissions(),
        _ => return "[]".to_string(),
    };
    let strs: Vec<&str> = perms.iter().map(|p| p.as_str()).collect();
    serde_json::to_string(&strs).unwrap_or_else(|_| "[]".to_string())
}

/// Check if a role has a specific permission.
///
/// Returns `true` if `role` (e.g. `"editor"`) has the given `permission`
/// (e.g. `"write"`). Unknown roles or permissions return `false`.
#[cfg_attr(feature = "wasm", wasm_bindgen)]
pub fn role_has_permission(role: &str, permission: &str) -> bool {
    let doc_role = match role {
        "owner" => DocumentRole::Owner,
        "editor" => DocumentRole::Editor,
        "viewer" => DocumentRole::Viewer,
        _ => return false,
    };
    let target = match permission {
        "read" => Permission::Read,
        "write" => Permission::Write,
        "delete" => Permission::Delete,
        "manage" => Permission::Manage,
        "approve" => Permission::Approve,
        _ => return false,
    };
    doc_role.permissions().contains(&target)
}

